  std::string title;
  std::string author;
  int year;
  std::string genre;
  double price;
};

struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        return {}; // Return empty vector on connection failure
    }
    auto conn = *conn_result;

    // Build the base query
    auto query = sqlgen::read<std::vector<Book>>;

    // Construct WHERE conditions dynamically
    auto conditions = sqlgen::where(true); // Start with true condition

    if (filters.title_keyword) {
        conditions = conditions && ("title"_c.like(*filters.title_keyword));
    }

    if (filters.min_year) {
        conditions = conditions && ("year"_c >= *filters.min_year);
    }

    if (filters.genre) {
        conditions = conditions && ("genre"_c == *filters.genre);
    }

    if (filters.max_price) {
        conditions = conditions && ("price"_c <= *filters.max_price);
    }

    // Apply the conditions to the query
    auto full_query = query | conditions;

    // Execute the query and return results
    auto result = full_query(conn);
    if (result) {
        return *result;
    } else {
        return {}; // Return empty vector on query execution failure
    }
}

}  // namespace query_search_books_by_criteria
