#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
    // Connect to the SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        return false;
    }
    auto conn = *conn_result;

    // Start a transaction for atomicity
    auto trans_result = conn->begin_transaction();
    if (!trans_result) {
        return false;
    }

    bool success = true;

    // Use batched updates with transaction for each document ID
    for (auto id : ids) {
        using namespace sqlgen::literals;

        // Create update statement with set operations for is_deleted and deleted_at
        auto stmt = sqlgen::update<Document>("is_deleted"_c.set(1), 
                                            "deleted_at"_c.set(sqlgen::CURRENT_TIMESTAMP))
                    | sqlgen::where("doc_id"_c == id);

        // Execute the update statement
        auto res = stmt(*conn);
        if (!res) {
            success = false;
            break;
        }
    }

    if (success) {
        // Commit the transaction if all updates succeeded
        auto commit_result = conn->commit();
        if (!commit_result) {
            success = false;
        }
    } else {
        // Rollback the transaction if any update failed
        auto rollback_result = conn->rollback();
        // Ignore rollback result - we're already returning false
    }

    return success;
}

}  // namespace soft_delete_records
```

