        where("account_id"_c == from_account_id)
    );

    if (!from_account_result) {
      conn->rollback();
      return false;
    }

    auto from_account = from_account_result.value();

    // 4. Check if from_account has sufficient funds
    if (from_account.balance < amount) {
      conn->rollback();
      return false;
    }

    // 5. Update from_account (balance = balance - amount)
    auto update_from_result = (conn->update<Account>(
        "balance"_c.set("balance"_c - amount)
    ) | where("account_id"_c == from_account_id && "balance"_c >= amount))(conn);

    if (!update_from_result) {
      conn->rollback();
      return false;
    }

    // 6. Update to_account (balance = balance + amount)
    auto update_to_result = (conn->update<Account>(
        "balance"_c.set("balance"_c + amount)
    ) | where("account_id"_c == to_account_id))(conn);

    if (!update_to_result) {
      conn->rollback();
      return false;
    }

    // 7. Commit transaction if all updates succeed
    auto commit_result = conn->commit();
    if (!commit_result) {
      conn->rollback();
      return false;
    }

    return true;

  } catch (...) {
    // 8. Rollback if any operation fails
    conn->rollback();
    return false;
  }
}

}  // namespace transaction_transfer_funds
```

