bool upsert_inventory_items(const std::vector<Inventory>& items) {
  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false; // Connection failed
  }

  // Perform upsert operation using sqlgen::write with sqlgen::upsert modifier
  auto write_result = (sqlgen::write(items) | sqlgen::upsert)(conn_result.value());
  if (!write_result) {
    return false; // Upsert operation failed
  }

  // Read back items to verify upsert behavior
  auto read_result = sqlgen::read<std::vector<Inventory>>(write_result.value());
  if (!read_result) {
    return false; // Read operation failed
  }

  // Verify that the number of items matches the input size
  return read_result.value().size() == items.size();
}

}  // namespace upsert_inventory_items
