};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen::literals;

  // Create SQLite connection
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Drop tables if they exist
  (sqlgen::drop<User> | sqlgen::if_exists)(conn);
  (sqlgen::drop<Friendship> | sqlgen::if_exists)(conn);

  // Create tables
  (sqlgen::create_table<User> | sqlgen::if_not_exists)(conn);
  (sqlgen::create_table<Friendship> | sqlgen::if_not_exists)(conn);

  // Write data to database
  sqlgen::write(conn, users);
  sqlgen::write(conn, friendships);

  // Query 1: Mutual friends using SELF-JOIN
  auto mutual_friends_query = sqlgen::read<std::vector<FriendConnection>>
      | sqlgen::select_from<User, "u1"_t1>("username"_t1 | sqlgen::as<"user1_name">, 
                                           "username"_t2 | sqlgen::as<"user2_name">)
      | sqlgen::inner_join<Friendship, "f1"_t3>("user_id"_t1 == "user_id1"_t3)
      | sqlgen::inner_join<Friendship, "f2"_t4>("user_id2"_t3 == "user_id1"_t4)
      | sqlgen::inner_join<User, "u2"_t2>("user_id2"_t4 == "user_id"_t2)
      | sqlgen::where("user_id"_t1 < "user_id"_t2)
      | sqlgen::group_by("user_id"_t1, "user_id"_t2)
      | sqlgen::having(sqlgen::count() > 0);

  auto mutual_results = mutual_friends_query(conn).value();

  // Query 2: Users with more than average friends using nested query
  auto avg_friends_query = sqlgen::read<std::vector<FriendConnection>>
      | sqlgen::select_from<User, "u"_t1>("username"_t1 | sqlgen::as<"user1_name">, 
                                          sqlgen::count("user_id"_t1) | sqlgen::as<"friend_count">)
      | sqlgen::left_join<Friendship, "f"_t2>("user_id"_t1 == "user_id1"_t2)
      | sqlgen::where(sqlgen::count() > 
          (sqlgen::select_from<User, "u2"_t5>(sqlgen::avg(sqlgen::count("user_id"_t5)) | sqlgen::as<"avg_friends">)
           | sqlgen::left_join<Friendship, "f2"_t6>("user_id"_t5 == "user_id1"_t6)
           | sqlgen::group_by("user_id"_t5)
          ).value());

