      | sqlgen::group_by("user_id"_t1, "user_id"_t4)
      | sqlgen::having(sqlgen::count() == 1);

  auto foaf_results = friend_of_friend_query(conn).value();

  // Query 4: Most connected users
  auto most_connected_query = sqlgen::read<std::vector<FriendConnection>>
      | sqlgen::select_from<User, "u"_t1>("username"_t1 | sqlgen::as<"user1_name">, 
                                          sqlgen::count("user_id"_t1) | sqlgen::as<"friend_count">)
      | sqlgen::left_join<Friendship, "f"_t2>("user_id"_t1 == "user_id1"_t2)
      | sqlgen::order_by(sqlgen::count().desc())
      | sqlgen::limit(10);

  auto most_connected = most_connected_query(conn).value();

  // Query 5: Same city recommendations
  auto same_city_query = sqlgen::read<std::vector<FriendConnection>>
      | sqlgen::select_from<User, "u1"_t1>("username"_t1 | sqlgen::as<"user1_name">, 
                                           "username"_t2 | sqlgen::as<"user2_name">)
