      | sqlgen::group_by("user_id"_t1, "user_id"_t2);

  auto same_city_results = same_city_query(conn).value();

  // Combine all results
  std::vector<FriendConnection> all_results;
  all_results.insert(all_results.end(), mutual_results.begin(), mutual_results.end());
  all_results.insert(all_results.end(), avg_results.begin(), avg_results.end());
  all_results.insert(all_results.end(), foaf_results.begin(), foaf_results.end());
  all_results.insert(all_results.end(), same_city_results.begin(), same_city_results.end());

  return all_results;
}

